const TOSSUP_MIN = -130;
const TOSSUP_MAX = 130;
const EXTREME_FAVORITE_CUTOFF = -300;
const UNDERDOG_MIN = 131;
const UNDERDOG_MAX = 260;

const BUCKETS = {
  watch_low:  [131, 135],
  slight:     [136, 150],
  prime:      [151, 160],
  moderate:   [161, 190],
  heavy:      [191, 220],
  very_heavy: [241, 249],
  watch_high: [250, 260],
};
const TRACK_ONLY_BUCKETS = ['watch_low'];

function getBucket(odds) {
  for (const label in BUCKETS) {
    const low  = BUCKETS[label][0];
    const high = BUCKETS[label][1];
    if (odds >= low && odds <= high) return label;
  }
  return 'out_of_range';
}

const events = $input.first().json.body;
const today = new Date().toISOString().split('T')[0];

const stats = {
  total: events.length,
  no_odds: 0, no_sides: 0, tossup: 0, extreme: 0,
  out_of_range: 0, qualified: 0, watch_only: 0
};

const qualifying = [];

for (const event of events) {
  const home = event.home_team;
  const away = event.away_team;
  const teamOdds = {};
  teamOdds[home] = { prices: [], books: {} };
  teamOdds[away] = { prices: [], books: {} };

  for (const bookmaker of (event.bookmakers || [])) {
    for (const market of (bookmaker.markets || [])) {
      if (market.key !== 'h2h') continue;
      for (const outcome of market.outcomes) {
        if (teamOdds[outcome.name]) {
          teamOdds[outcome.name].prices.push(outcome.price);
          teamOdds[outcome.name].books[bookmaker.key] = outcome.price;
        }
      }
    }
  }

  if (!teamOdds[home].prices.length || !teamOdds[away].prices.length) {
    stats.no_odds++;
    continue;
  }

  const homeBest = Math.max.apply(null, teamOdds[home].prices);
  const awayBest = Math.max.apply(null, teamOdds[away].prices);

  let favorite, underdog;
  if (homeBest < awayBest) {
    favorite = home; underdog = away;
  } else if (awayBest < homeBest) {
    favorite = away; underdog = home;
  } else {
    stats.no_sides++;
    continue;
  }

  const favBest = Math.max.apply(null, teamOdds[favorite].prices);
  const dogBest = Math.max.apply(null, teamOdds[underdog].prices);

  if (favBest >= TOSSUP_MIN && favBest <= TOSSUP_MAX &&
      dogBest >= TOSSUP_MIN && dogBest <= TOSSUP_MAX) {
    stats.tossup++;
    continue;
  }

  if (favBest <= EXTREME_FAVORITE_CUTOFF) {
    stats.extreme++;
    continue;
  }

  if (dogBest < UNDERDOG_MIN || dogBest > UNDERDOG_MAX) {
    stats.out_of_range++;
    continue;
  }

  const dogPrices = teamOdds[underdog].prices;
  const favPrices = teamOdds[favorite].prices;
  const dogAvg = Math.round(dogPrices.reduce(function(a, b) { return a + b; }, 0) / dogPrices.length * 10) / 10;
  const favAvg = Math.round(favPrices.reduce(function(a, b) { return a + b; }, 0) / favPrices.length * 10) / 10;

  const dogBooks = teamOdds[underdog].books;
  const bookEntries = Object.keys(dogBooks);
  let bestBook = '';
  let bestPrice = -Infinity;
  for (let i = 0; i < bookEntries.length; i++) {
    if (dogBooks[bookEntries[i]] > bestPrice) {
      bestPrice = dogBooks[bookEntries[i]];
      bestBook = bookEntries[i];
    }
  }

  const bucket = getBucket(dogBest);
  const isTrackOnly = TRACK_ONLY_BUCKETS.indexOf(bucket) !== -1;

  if (isTrackOnly) stats.watch_only++;
  else stats.qualified++;

  qualifying.push({
    json: {
      date: today,
      game_id: event.id,
      commence_time: event.commence_time || '',
      home_team: home,
      away_team: away,
      favorite: favorite,
      underdog: underdog,
      dog_odds_best: dogBest,
      dog_odds_avg: dogAvg,
      dog_best_book: bestBook,
      fav_odds_best: favBest,
      fav_odds_avg: favAvg,
      home_is_dog: underdog === home,
      bucket: bucket,
      num_books: (event.bookmakers || []).length,
      winner: '',
      dog_won: '',
      profit: '',
      _is_track_only: isTrackOnly,
    }
  });
}

if (qualifying.length === 0) {
  return [{ json: { _no_games: true, _stats: stats } }];
}

qualifying[0].json._stats = stats;
qualifying[0].json._wager_count = qualifying.filter(function(q) { return !q.json._is_track_only; }).length;
qualifying[0].json._watch_count  = qualifying.filter(function(q) { return  q.json._is_track_only; }).length;

return qualifying;

// Pitcher Flag Enrichment
// Fetches today's MLB probable pitchers and current season WHIP stats.
// Adds top_pitcher_flag, fav_starter_name, fav_starter_whip to each game.
// Games where the favorite's starter has WHIP <= threshold get flagged.

const WHIP_THRESHOLD = 1.10;
const MIN_IP = 25;
const TODAY = new Date().toISOString().split('T')[0];
const SEASON = new Date().getFullYear();

function normTeam(name) {
  if (!name) return '';
  const map = {
    'Athletics': 'athletics', 'Oakland Athletics': 'athletics',
    'Arizona Diamondbacks': 'd-backs', 'D-backs': 'd-backs',
    'Chicago White Sox': 'white sox', 'Chicago Cubs': 'cubs',
    'New York Yankees': 'yankees', 'New York Mets': 'mets',
    'Los Angeles Dodgers': 'dodgers', 'Los Angeles Angels': 'angels',
    'San Francisco Giants': 'giants', 'Tampa Bay Rays': 'rays',
    'Boston Red Sox': 'red sox', 'Toronto Blue Jays': 'blue jays',
    'Kansas City Royals': 'royals', 'Minnesota Twins': 'twins',
    'Cleveland Guardians': 'guardians', 'Detroit Tigers': 'tigers',
    'Milwaukee Brewers': 'brewers', 'St. Louis Cardinals': 'cardinals',
    'Cincinnati Reds': 'reds', 'Pittsburgh Pirates': 'pirates',
    'Philadelphia Phillies': 'phillies', 'Atlanta Braves': 'braves',
    'Miami Marlins': 'marlins', 'Washington Nationals': 'nationals',
    'Colorado Rockies': 'rockies', 'San Diego Padres': 'padres',
    'Seattle Mariners': 'mariners', 'Houston Astros': 'astros',
    'Texas Rangers': 'rangers', 'Baltimore Orioles': 'orioles',
  };
  if (map[name]) return map[name];
  return name.trim().split(' ').pop().toLowerCase();
}

// Fetch MLB schedule with probable pitchers
let schedule = [];
try {
  const schedRes = await fetch(
    'https://statsapi.mlb.com/api/v1/schedule?sportId=1&date=' + TODAY + '&hydrate=probablePitcher'
  );
  const schedData = await schedRes.json();
  for (const dateEntry of (schedData.dates || [])) {
    for (const g of (dateEntry.games || [])) {
      schedule.push({
        gamePk: g.gamePk,
        homeName: g.teams.home.team.name,
        awayName: g.teams.away.team.name,
        homeProbId:   ((g.teams.home.probablePitcher) || {}).id   || null,
        awayProbId:   ((g.teams.away.probablePitcher) || {}).id   || null,
        homeProbName: ((g.teams.home.probablePitcher) || {}).fullName || null,
        awayProbName: ((g.teams.away.probablePitcher) || {}).fullName || null,
      });
    }
  }
} catch (e) {
  // schedule lookup failed — all games get flag = null
}

// Fetch pitcher season stats
const pitcherStats = {};
try {
  const statsRes = await fetch(
    'https://statsapi.mlb.com/api/v1/stats?stats=season&group=pitching&season=' + SEASON + '&sportId=1&limit=1000'
  );
  const statsData = await statsRes.json();
  const splits = (((statsData.stats || [])[0]) || {}).splits || [];
  for (const s of splits) {
    const pid  = (s.player || {}).id;
    if (!pid) continue;
    const ip   = parseFloat(s.stat.inningsPitched || 0);
    const whip = parseFloat(s.stat.whip || 99);
    if (ip >= MIN_IP) {
      pitcherStats[pid] = {
        name: (s.player || {}).fullName || '',
        whip: whip,
        ip: ip,
      };
    }
  }
} catch (e) {
  // pitcher stats lookup failed
}

// Match each game and add flag
const items = $input.all();
const output = [];

for (let idx = 0; idx < items.length; idx++) {
  const g = items[idx].json;

  const homeNorm = normTeam(g.home_team);
  const awayNorm = normTeam(g.away_team);
  let matched = null;

  for (let si = 0; si < schedule.length; si++) {
    const sg = schedule[si];
    const sgHome = normTeam(sg.homeName);
    const sgAway = normTeam(sg.awayName);
    if (sgHome === homeNorm && sgAway === awayNorm) {
      matched = sg;
      break;
    }
    if ((sgHome.indexOf(homeNorm) !== -1 || homeNorm.indexOf(sgHome) !== -1) &&
        (sgAway.indexOf(awayNorm) !== -1 || awayNorm.indexOf(sgAway) !== -1)) {
      matched = sg;
      break;
    }
  }

  let favStarterName = null;
  let favStarterWhip = null;
  let topPitcherFlag = null;

  if (matched) {
    const favNorm     = normTeam(g.favorite);
    const mlbHomeNorm = normTeam(matched.homeName);
    const favIsHome   = favNorm === mlbHomeNorm ||
                        mlbHomeNorm.indexOf(favNorm) !== -1 ||
                        favNorm.indexOf(mlbHomeNorm) !== -1;

    const favProbId   = favIsHome ? matched.homeProbId   : matched.awayProbId;
    favStarterName    = favIsHome ? matched.homeProbName : matched.awayProbName;

    if (favProbId && pitcherStats[favProbId]) {
      favStarterWhip = pitcherStats[favProbId].whip;
      topPitcherFlag = favStarterWhip <= WHIP_THRESHOLD;
    }
  }

  const enriched = {};
  const keys = Object.keys(g);
  for (let k = 0; k < keys.length; k++) { enriched[keys[k]] = g[keys[k]]; }
  enriched.fav_starter_name = favStarterName;
  enriched.fav_starter_whip = favStarterWhip;
  enriched.top_pitcher_flag = topPitcherFlag;

  output.push({ json: enriched });
}

return output;

const items = $input.all();
const stats = items[0].json._stats || {};
const today = new Date().toISOString().split('T')[0];

const wagerItems = items.filter(function(i) { return !i.json._is_track_only; });
const watchItems  = items.filter(function(i) { return  i.json._is_track_only; });
const flaggedItems = items.filter(function(i) { return i.json.top_pitcher_flag === true; });

let msg = '⚾ *MLB Underdog Report — ' + today + '*\n\n';
msg += '📊 *Filter Results:*\n';
msg += 'Games today: ' + (stats.total || '?') + '\n';
msg += 'Toss-ups: ' + (stats.tossup || 0) + ' | Extreme: ' + (stats.extreme || 0) + ' | Out of range: ' + (stats.out_of_range || 0) + '\n\n';

if (wagerItems.length > 0) {
  msg += '✅ *' + wagerItems.length + ' Qualifying Underdogs — WAGER:*\n\n';
  for (let i = 0; i < wagerItems.length; i++) {
    const g = wagerItems[i].json;
    const homeAway = g.home_is_dog ? '(Home)' : '(Away)';
    const pitcherNote = g.top_pitcher_flag === true
      ? ' ⚠️ Top pitcher: ' + (g.fav_starter_name || '?') + ' (' + (g.fav_starter_whip || '?') + ' WHIP)'
      : (g.fav_starter_name ? ' | Starter: ' + g.fav_starter_name : '');
    msg += '🔹 *' + g.underdog + '* ' + homeAway + ' +' + g.dog_odds_best + '\n';
    msg += '   vs ' + g.favorite + ' (' + g.fav_odds_best + ')\n';
    msg += '   Bucket: ' + g.bucket + ' | Best book: ' + g.dog_best_book + '\n';
    if (pitcherNote) msg += '   ' + pitcherNote + '\n';
    msg += '\n';
  }
} else {
  msg += 'No wager-eligible underdogs today.\n\n';
}

if (watchItems.length > 0) {
  msg += '👁 *' + watchItems.length + ' Watch-Only — track, do not wager:*\n';
  for (let i = 0; i < watchItems.length; i++) {
    const g = watchItems[i].json;
    msg += '   ' + g.underdog + ' +' + g.dog_odds_best + ' vs ' + g.favorite + ' | ' + g.bucket + '\n';
  }
  msg += '\n';
}

if (flaggedItems.length > 0) {
  msg += '🚩 *' + flaggedItems.length + ' game(s) facing a top pitcher (WHIP ≤ 1.10) — wager with caution*\n';
}

return [{ json: { message: msg } }];

const stats = $input.first().json._stats || {};
const today = new Date().toISOString().split('T')[0];

let msg = '⚾ *MLB Underdog Report — ' + today + '*\n\n';
msg += 'No qualifying underdogs today.\n\n';
msg += '📊 ' + (stats.total || '?') + ' games checked:\n';
msg += 'Toss-ups: ' + (stats.tossup || 0) + ' | Extreme: ' + (stats.extreme || 0) + ' | Out of range: ' + (stats.out_of_range || 0);

return [{ json: { message: msg } }];
